function esc(value = '') { return String(value).replace(/[&<>'"]/g, c => ({ '&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;' }[c])); }
function route() { return location.hash.replace(/^#\/?/, '').split('/')[0] || 'home'; }
function notice(message, type = 'success') { const el = document.createElement('div'); el.className = `toast ${type}`; el.setAttribute('role', type === 'error' ? 'alert' : 'status'); el.textContent = message; toasts.append(el); setTimeout(() => el.remove(), 4200); }
function dateBefore(days) { const d = new Date(); d.setDate(d.getDate() - days); return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`; }
function readable(value) { return String(value || '').replaceAll('_', ' ').replace(/\b\w/g, c => c.toUpperCase()); }
function fmt(value, digits = 2) { const number = Number(value); if (!Number.isFinite(number)) return '—'; if (!numberFormats.has(digits)) numberFormats.set(digits, new Intl.NumberFormat(undefined, { maximumFractionDigits: digits })); return numberFormats.get(digits).format(number); }
function fmtDate(value) { const date = new Date(value); return Number.isNaN(date.getTime()) ? '—' : dateTimeFormat.format(date); }
function confirmDiscard() { if (!state.dirty) return true; const subject=state.dirtyReason || 'changes'; if (!confirm(`Discard unsaved ${subject}?`)) return false; state.dirty = false; state.dirtyReason = null; return true; }
function setRoute(name) { if (confirmDiscard()) location.hash = `#/${name}`; }
function applyTheme(theme = localStorage.getItem('terry-theme') || 'dark') { const light = theme === 'light'; document.body.classList.toggle('light', light); document.documentElement.style.colorScheme = light ? 'light' : 'dark'; document.querySelector('meta[name="theme-color"]')?.setAttribute('content',light?'#f5f6f8':'#14151a'); }
async function api(path, options = {}) {
  const headers = { ...(options.body ? { 'Content-Type': 'application/json' } : {}), ...(options.headers || {}) };
  const response = await fetch(path, { ...options, headers, credentials:'same-origin' });
  const data = response.status === 204 ? {} : await response.json().catch(() => ({}));
  if (!response.ok) { const error = new Error(data.message || data.detail?.message || `Request failed (${response.status})`); error.status = response.status; throw error; }
  return data;
}
