function empty(title, text, action = '') { return `<div class="empty"><div class="empty-icon" aria-hidden="true">⌁</div><h2>${esc(title)}</h2><p>${esc(text)}</p>${action}</div>`; }
function statusPill(value) { return `<span class="pill ${esc(value)}">${esc(readable(value))}</span>`; }
function busy(button, on) { button.disabled = on; button.setAttribute('aria-busy', String(on)); button.dataset.label ||= button.textContent; button.textContent = on ? 'Working…' : button.dataset.label; }
function bindCodeEditor() {
  const editor=document.querySelector('#strategy-code'), gutter=document.querySelector('#line-numbers'), cursor=document.querySelector('#cursor-position');
  if(!editor)return;
  const refresh=()=>{const count=editor.value.split('\n').length;gutter.textContent=Array.from({length:count},(_,index)=>index+1).join('\n');const before=editor.value.slice(0,editor.selectionStart).split('\n');cursor.textContent=`Ln ${before.length}, Col ${before.at(-1).length+1}`;};
  const changed=()=>{state.dirty=true;state.dirtyReason='strategy changes';refresh();};
  editor.addEventListener('input',changed);
  ['click','keyup','select'].forEach(name=>editor.addEventListener(name,refresh));
  editor.addEventListener('scroll',()=>{gutter.scrollTop=editor.scrollTop;});
  editor.addEventListener('keydown',event=>{
    if((event.ctrlKey||event.metaKey)&&event.key.toLowerCase()==='s'){event.preventDefault();document.querySelector('#save')?.click();return;}
    const start=editor.selectionStart,end=editor.selectionEnd;
    if(event.key==='Enter'&&!event.shiftKey){event.preventDefault();const line=editor.value.slice(0,start).split('\n').at(-1);const indent=(line.match(/^\s*/)||[''])[0]+(line.trimEnd().endsWith(':')?'    ':'');editor.setRangeText(`\n${indent}`,start,end,'end');changed();return;}
    if(event.key!=='Tab')return;
    event.preventDefault();
    if(start===end&&!event.shiftKey){editor.setRangeText('    ',start,end,'end');changed();return;}
    const lineStart=editor.value.lastIndexOf('\n',start-1)+1;let lineEnd=editor.value.indexOf('\n',end);if(lineEnd<0)lineEnd=editor.value.length;
    const original=editor.value.slice(lineStart,lineEnd),lines=original.split('\n');
    const replacement=event.shiftKey?lines.map(line=>line.replace(/^ {1,4}/,'')).join('\n'):lines.map(line=>`    ${line}`).join('\n');
    editor.setRangeText(replacement,lineStart,lineEnd,'select');changed();
  });
  if(window.ResizeObserver)new ResizeObserver(()=>{gutter.style.height=`${editor.offsetHeight}px`;}).observe(editor);
  refresh();
}

