async function createStrategy() { if (!confirmDiscard()) return; const name = prompt('Strategy class name (for example EmaCross)'); if (!name) return; try { await api('/api/strategies', {method:'POST', body: JSON.stringify({name})}); state.strategy = name; notice('Strategy created'); render(); } catch (error) { notice(error.message, 'error'); } }
async function fileToBase64(file) {
  const bytes = new Uint8Array(await file.arrayBuffer());
  let binary = ''; const chunk = 0x8000;
  for (let i = 0; i < bytes.length; i += chunk) binary += String.fromCharCode(...bytes.subarray(i, i + chunk));
  return btoa(binary);
}

// Post an import payload, transparently handling the 409 name-conflict prompt (rename or overwrite).
async function postImport(payload) {
  try {
    let result;
    try { result = await api('/api/strategies/import', { method: 'POST', body: JSON.stringify(payload) }); }
    catch (error) {
      if (error.status !== 409) throw error;
      const choice = prompt('A strategy with that name already exists.\nEnter a different name to import as a copy, or leave blank to overwrite it:');
      if (choice === null) return;
      const retry = choice.trim() ? { ...payload, name: choice.trim() } : { ...payload, overwrite: true };
      result = await api('/api/strategies/import', { method: 'POST', body: JSON.stringify(retry) });
    }
    state.strategy = result.name;
    notice(result.validation_error ? `Imported ${result.name}; resolve its validation warning before running.` : `Imported ${result.name}`);
    render();
  } catch (error) { notice(error.message, 'error'); }
}

async function importStrategyZip(file) {
  try { await postImport({ data: await fileToBase64(file) }); }
  catch (error) { notice(error.message, 'error'); }
}

async function importStrategyFolder(fileList) {
  try {
    // Skip caches / OS junk up front so a big folder doesn't blow the file cap.
    const picked = fileList.filter(f => {
      const rel = f.webkitRelativePath || f.name;
      return !/(^|\/)(__pycache__|\.DS_Store|Thumbs\.db)(\/|$)/.test(rel) && !/\.(pyc|pyo)$/.test(rel);
    });
    if (!picked.length) { notice('That folder has no strategy files.', 'error'); return; }
    if (picked.length > 400) { notice('That folder has too many files to import.', 'error'); return; }
    const files = await Promise.all(picked.map(async f => ({
      path: f.webkitRelativePath || f.name, data: await fileToBase64(f),
    })));
    await postImport({ files });
  } catch (error) { notice(error.message, 'error'); }
}

async function candles() {
  const data = await api('/api/candles'); const exchanges = data.exchanges.map(v => `<option>${esc(v)}</option>`).join('');
  shell('Import Candles', `<div class="two-col"><section class="panel"><div class="panel-head"><div><h2>Import Historical Data</h2><p>One-minute candles from supported public exchange APIs are stored locally and aggregated for research.</p></div></div><form id="import-form" class="form-grid" autocomplete="off"><label>Exchange<select name="exchange">${exchanges}</select></label><label>Symbol<input name="symbol" value="BTC-USDT" pattern="[A-Za-z0-9]+-[A-Za-z0-9]+" autocomplete="off" spellcheck="false" required></label><label>Start Date<input name="start_date" type="date" value="${dateBefore(180)}" required></label><label>Finish Date <span class="optional">optional</span><input name="finish_date" type="date" value="${dateBefore(1)}"></label><div class="form-actions"><button class="primary">Start Import <span aria-hidden="true">→</span></button></div></form><div id="import-progress" aria-live="polite"></div></section><section class="panel"><div class="panel-head"><div><h2>Stored Datasets</h2><p>${data.existing.length} exchange-symbol pairs available.</p></div></div>${data.existing.length ? `<div class="table-wrap"><table><thead><tr><th>Exchange</th><th>Symbol</th><th>Coverage</th><th>Candles</th><th><span class="sr-only">Actions</span></th></tr></thead><tbody>${data.existing.map(row => `<tr><td>${esc(row.exchange)}</td><td><code>${esc(row.symbol)}</code></td><td>${esc(row.start_date)} — ${esc(row.finish_date)}</td><td>${fmt(row.count,0)}</td><td><button class="icon-button delete-data" data-exchange="${esc(row.exchange)}" data-symbol="${esc(row.symbol)}" aria-label="Delete ${esc(row.symbol)} candles">×</button></td></tr>`).join('')}</tbody></table></div>` : empty('No data imported', 'Import candles to start a backtest.')}</section></div>`, 'Imports run in the background; progress is checked automatically.');
  document.querySelector('#import-form').addEventListener('submit', beginImport);
  document.querySelectorAll('.delete-data').forEach(button => button.addEventListener('click', async () => { if (!confirm(`Delete all ${button.dataset.symbol} candles for ${button.dataset.exchange}?`)) return; try { await api(`/api/candles/${encodeURIComponent(button.dataset.exchange)}/${encodeURIComponent(button.dataset.symbol)}`, {method:'DELETE'}); notice('Candle data deleted'); render(); } catch (error) { notice(error.message,'error'); } }));
  // Re-attach the progress bar to any import still running on the backend, even after a
  // full page reload wiped the browser's in-memory import id.
  if (!state.importId && data.active_imports?.length) state.importId = data.active_imports[0].import_id;
  if (state.importId) startImportWatch();
}
async function beginImport(event) { event.preventDefault(); const button = event.currentTarget.querySelector('button'); busy(button,true); try { const data = await api('/api/candles/import',{method:'POST',body:JSON.stringify(Object.fromEntries(new FormData(event.currentTarget)))}); state.importId=data.import_id; notice('Import started; checking progress…'); startImportWatch(); } catch(error) { notice(error.message,'error'); } finally { busy(button,false); } }
function startImportWatch(){const gen=++importGen;watchImport(gen);}
async function watchImport(gen){ if(gen!==importGen || !state.importId) return; const box=document.querySelector('#import-progress'); if(!box) return; const importId=state.importId; try { const data=await api(`/api/candles/import/${importId}`); if(gen!==importGen) return; const target=document.querySelector('#import-progress'); if(!target) return; const progress=Math.max(0,Math.min(100,Number(data.progress)||0)); target.innerHTML=`<div class="progress-card"><div><strong>${esc(readable(data.status))}</strong><span>${esc(data.message || '')}</span></div><div class="progress" role="progressbar" aria-label="Candle import progress" aria-valuemin="0" aria-valuemax="100" aria-valuenow="${progress}"><i style="width:${progress}%"></i></div><small>${fmt(data.candles_imported||0,0)} candles · ${progress}%</small>${['started','running'].includes(data.status)?'<button class="danger-text" id="cancel-import">Cancel Import</button>':''}</div>`; document.querySelector('#cancel-import')?.addEventListener('click',async()=>{if(!confirm('Cancel this candle import?'))return;try{await api(`/api/candles/import/${importId}/cancel`,{method:'POST'});notice('Cancel requested');}catch(error){notice(error.message,'error');}}); if(['started','running'].includes(data.status)) setTimeout(()=>watchImport(gen),1200); else { state.importId=null; if(data.status==='finished'){notice('Candle import finished');setTimeout(render,450);} else notice(data.message||'Candle import stopped','error'); } } catch(error){ if(gen===importGen){state.importId=null;notice(error.message,'error');} } }

// Sorted low → high; 1w and 1M included so every timeframe field offers them.
const TIMEFRAMES=['1m','5m','15m','30m','45m','1h','2h','3h','4h','6h','8h','12h','1d','1w','1M'];
function tfOptions(sel='4h'){return TIMEFRAMES.map(t=>`<option ${t===sel?'selected':''}>${t}</option>`).join('');}
function routeRow(strategyOptions,trading){return `<div class="route-row">${trading?`<select class="r-strategy" aria-label="Route strategy">${strategyOptions}</select>`:''}<input class="r-symbol" placeholder="ETH-USDT" value="" spellcheck="false" autocomplete="off" aria-label="Route symbol"><select class="r-timeframe" aria-label="Route timeframe">${tfOptions()}</select><button type="button" class="icon-button r-remove" aria-label="Remove route">×</button></div>`;}
function demoForm(){return `<form class="form-grid research-form" id="research-form" autocomplete="off"><label>Strategy<select name="strategy" required><option value="">Select strategy…</option></select></label><label>Exchange<select name="exchange"></select></label><label>Symbol<input name="symbol" value="BTC-USDT" autocomplete="off" spellcheck="false" required></label><label>Timeframe<select name="timeframe">${tfOptions('1h')}</select></label><label>Starting Paper Balance<input type="number" inputmode="decimal" name="starting_balance" min="1" step="any" value="10000" required></label><label>Fee Rate<input type="number" inputmode="decimal" name="fee" min="0" max="1" step="0.0001" value="0.0006"></label><label>Leverage<input type="number" inputmode="decimal" name="futures_leverage" min="1" step="any" value="2"></label><label>History Lookback <span class="optional">days</span><input type="number" inputmode="numeric" name="lookback_days" min="1" max="365" step="1" value="14" required></label><label class="wide-label">Session Title <span class="optional">optional</span><input name="title" maxlength="160" autocomplete="off" placeholder="Name this live demo…"></label><label class="wide-label">Notes <span class="optional">optional</span><textarea name="description" maxlength="20000" placeholder="What are you paper-trading and why?"></textarea></label><div class="wide-label live-demo-note">◈ Trades a rolling window of live market data with paper money — fetches fresh candles for the chosen symbol/timeframe and keeps replaying the strategy as new candles close. Press Stop any time; all backtest stats and charts are available below.</div><div class="form-actions"><button class="primary">Start Live Demo <span aria-hidden="true">→</span></button></div></form>`;}
function researchForm(mode) { if(mode==='demo') return demoForm(); const common=`<label>Strategy<select name="strategy" required><option value="">Select strategy…</option></select></label><label>Exchange<select name="exchange"></select></label><label>Symbol<input name="symbol" value="BTC-USDT" autocomplete="off" spellcheck="false" required></label><label>Timeframe<select name="timeframe">${tfOptions('4h')}</select></label><label>Start Date<input type="date" name="start_date" value="${dateBefore(365)}" required></label><label>Finish Date<input type="date" name="finish_date" value="${dateBefore(1)}" required></label><label class="wide-label">Session Title <span class="optional">optional</span><input name="title" maxlength="160" autocomplete="off" placeholder="What are you testing?"></label><label class="wide-label">Research Notes <span class="optional">optional</span><textarea name="description" maxlength="20000" placeholder="Hypothesis, change, or rationale…"></textarea></label>`;
  const workers=mode==='backtest'?'':`<label>CPU Cores <span class="optional">auto</span><input type="number" inputmode="numeric" name="cpu_cores" min="1" placeholder="80% of available"></label>`;
  const routes=`<details class="route-builder" id="routing-menu"><summary>Routing menu — extra routes &amp; market data</summary><p>Add trading routes to test several strategy · symbol · timeframe combinations at once. Leave empty to use the single route above. All routes share the exchange selected above.</p><div class="routes-head"><h5>Trading routes</h5><button type="button" class="secondary small" id="add-route">＋ Add route</button></div><div id="routes-list" class="routes-list"></div><div class="routes-head"><h5>Data routes <span class="optional">extra candles only</span></h5><button type="button" class="secondary small" id="add-data-route">＋ Add data route</button></div><div id="data-routes-list" class="routes-list"></div></details>`;
  const extra=mode==='optimization'?`<label>Objective<select name="objective"><option>sharpe</option><option>calmar</option><option>sortino</option><option>omega</option><option>serenity</option><option>smart sharpe</option><option>smart sortino</option><option>net_profit_percentage</option></select></label><label>Trials<input type="number" inputmode="numeric" name="n_trials" min="1" value="30"></label><label>Training Split<input type="number" inputmode="decimal" name="train_test_split" min="0.11" max="0.89" step="0.01" value="0.75"></label><label>Target Trades<input type="number" inputmode="numeric" name="optimal_total" min="2" value="200"></label><label>Best Candidates<input type="number" inputmode="numeric" name="best_candidates_count" min="1" value="20"></label>`:mode==='monte'?`<label>Scenarios<input type="number" inputmode="numeric" name="num_scenarios" min="1" value="200"></label><label>Candle Pipeline<select name="pipeline_type"><option value="moving_block_bootstrap">Moving Block Bootstrap</option><option value="gaussian_resampler">Gaussian Resampler</option><option value="gaussian_noise">Gaussian Noise</option></select></label><label class="check"><input type="checkbox" name="run_candles" checked> Candle Resampling</label><label class="check"><input type="checkbox" name="run_trades"> Trade-Order Shuffling</label><label class="check"><input type="checkbox" name="fast_mode" checked> Fast Mode</label><label class="wide-label">Pipeline Parameters JSON<textarea name="pipeline_params_json" spellcheck="false">{"batch_size":10080}</textarea></label>`:mode==='rule'?`<label>Simulations<input type="number" inputmode="numeric" name="n_simulations" min="2000" value="2000"></label><label>Random Seed <span class="optional">optional</span><input type="number" inputmode="numeric" name="random_seed" min="0" placeholder="42"></label><label class="wide-label">Hypothesis<input name="hypothesis" autocomplete="off" placeholder="Describe the expected entry edge…"></label>`:`<label class="check"><input type="checkbox" name="benchmark" checked> Buy-and-Hold Benchmark</label><label class="check"><input type="checkbox" name="export_chart" checked> PNG Chart Pack</label><label class="check"><input type="checkbox" name="export_csv"> Embed CSV Export</label><label class="check"><input type="checkbox" name="export_json"> Embed JSON Export</label><label class="check"><input type="checkbox" name="export_tradingview"> TradingView Pine Export</label><label class="check"><input type="checkbox" name="debug_mode"> Debug Logs</label>`;
  return `<form class="form-grid research-form" id="research-form" autocomplete="off">${common}${workers}${extra}${routes}<div class="form-actions"><button class="primary">Run ${esc(modes[mode].label)} <span aria-hidden="true">→</span></button></div></form>`;
}
async function research(mode) {
  const kind=modes[mode].endpoint, title=modes[mode].label; const [strategies, config, sessions] = await Promise.all([api('/api/strategies'),api('/api/config'),api(`/api/sessions/${kind}?limit=12`)]);
  const selected=state.session && state.session.kind===kind ? state.session : null;
  const desc=mode==='rule'?'Validate an entry rule first; require a p-value below 0.05 to proceed.':mode==='monte'?'Test whether the observed result survives resampled price paths.':mode==='optimization'?'Search parameters on a training window and validate candidates out of sample.':mode==='demo'?'Paper-trade a strategy on historical data with a paper-money account you fund and can top up or withdraw, then review the full report.':'Run a no-look-ahead historical simulation with full trade, chart, and metric output.';
  shell(title, `<div class="research-stack"><section class="panel runner"><div class="panel-head"><div><h2>New ${esc(title)}</h2><p>${desc}</p></div></div>${strategies.strategies.length ? researchForm(mode) : empty('Create a strategy first', 'A research run needs a strategy source file.', '<button class="primary" data-route="strategies">Open Strategies</button>')}</section><section class="panel result-panel" id="active-session" aria-live="polite">${selected ? renderSession(selected) : empty('No active result', 'Run a session or open one from the recent history below.')}</section><section class="panel history"><div class="panel-head"><div><h2>Recent Sessions</h2><p>${sessions.total} saved ${esc(title.toLowerCase())} sessions.</p></div><input id="session-search" name="session_search" autocomplete="off" aria-label="Search session history" placeholder="Search history…"></div>${sessions.sessions.length ? sessionTable(sessions.sessions, selected?.session_id) : '<p class="muted padded">Nothing here yet.</p>'}</section></div>`, 'Research runs execute locally and persist results, notes, reports, and exports.');
  const form=document.querySelector('#research-form');
  if(form){
    const options=strategies.strategies.map(s=>`<option value="${esc(s.name)}" ${s.name===state.strategy&&!s.validation_error?'selected':''} ${s.validation_error?'disabled':''}>${esc(s.name)}${s.validation_error?' — fix validation error':''}</option>`).join('');
    form.querySelector('[name=strategy]').insertAdjacentHTML('beforeend',options);
    form.querySelector('[name=exchange]').innerHTML=state.status.supported_exchanges.map(v=>`<option ${v===config.config.exchange?'selected':''}>${esc(v)}</option>`).join('');
    const stratOpts=strategies.strategies.filter(s=>!s.validation_error).map(s=>`<option>${esc(s.name)}</option>`).join('');
    const routesList=form.querySelector('#routes-list'), dataList=form.querySelector('#data-routes-list');
    const syncRequired=()=>{const strat=form.querySelector('[name=strategy]');if(strat)strat.required=!(routesList&&routesList.children.length);};
    const addRow=(list,trading)=>{if(!list)return;list.insertAdjacentHTML('beforeend',routeRow(stratOpts,trading));const row=list.lastElementChild;row.querySelector('.r-remove').addEventListener('click',()=>{row.remove();syncRequired();});syncRequired();};
    form.querySelector('#add-route')?.addEventListener('click',()=>addRow(routesList,true));
    form.querySelector('#add-data-route')?.addEventListener('click',()=>addRow(dataList,false));
    form.addEventListener('submit',event=>beginResearch(event,kind));
  }
  document.querySelectorAll('[data-session]').forEach(button=>button.addEventListener('click',()=>loadSession(button.dataset.session)));
  document.querySelectorAll('[data-route]').forEach(el=>el.addEventListener('click',()=>setRoute(el.dataset.route)));
  document.querySelector('#session-search')?.addEventListener('input',event=>filterTable(event.target.value));
  const activeEl=document.querySelector('#active-session');
  if(selected){ if(selected.status==='running') startWatch(selected.session_id); else mountSessionCharts(activeEl,selected); }
}
function sessionTable(rows,selectedId){return `<div class="table-wrap"><table id="session-table"><thead><tr><th>Research Session</th><th>Strategy</th><th>Market</th><th>Status</th><th>Updated</th><th><span class="sr-only">Actions</span></th></tr></thead><tbody>${rows.map(s=>{const title=s.notes_metadata?.title||`${readable(s.kind)} · ${s.state.strategy}`;const on=s.session_id===selectedId;return `<tr class="${on?'selected':''}" data-search="${esc(`${s.session_id} ${title} ${s.state.strategy} ${s.state.symbol} ${s.notes}`)}"><td>${on?'<span class="row-open" aria-label="Currently open" title="Currently open">●</span> ':''}<strong>${esc(title)}</strong><br><code>${esc(s.session_id.slice(0,8))}</code></td><td>${esc(s.state.strategy)}</td><td>${esc(s.state.symbol)} · ${esc(s.state.timeframe)}</td><td>${statusPill(s.status)}</td><td>${esc(fmtDate(s.updated_at))}</td><td><div class="button-row"><button class="secondary small ${on?'active':''}" data-session="${esc(s.session_id)}" aria-label="Open session ${esc(s.session_id.slice(0,8))}">${on?'Opened':'Open'}</button><button class="danger-text small" data-delete-session="${esc(s.session_id)}" aria-label="Delete session ${esc(s.session_id.slice(0,8))}">Delete</button></div></td></tr>`;}).join('')}</tbody></table></div>`;}
function filterTable(query){document.querySelectorAll('#session-table tbody tr').forEach(row=>row.hidden=!row.dataset.search.toLowerCase().includes(query.toLowerCase()));}
async function beginResearch(event,kind){event.preventDefault();if(!confirmDiscard())return;const form=event.currentTarget;const button=form.querySelector('button');busy(button,true);try{const values=Object.fromEntries(new FormData(form));const gather=(sel,trading)=>[...form.querySelectorAll(`${sel} .route-row`)].map(r=>{const o={symbol:(r.querySelector('.r-symbol').value||'').toUpperCase().trim(),timeframe:r.querySelector('.r-timeframe').value};if(trading)o.strategy=r.querySelector('.r-strategy').value;return o;}).filter(o=>o.symbol);const tRoutes=gather('#routes-list',true),dRoutes=gather('#data-routes-list',false);if(tRoutes.length)values.routes=tRoutes;if(dRoutes.length)values.data_routes=dRoutes;const pipelineRaw=values.pipeline_params_json?.trim();delete values.pipeline_params_json;if(pipelineRaw){values.pipeline_params=JSON.parse(pipelineRaw);if(!values.pipeline_params||Array.isArray(values.pipeline_params)||typeof values.pipeline_params!=='object')throw new Error('Pipeline Parameters JSON must be an object');}Object.keys(values).forEach(name=>{if(values[name]==='')delete values[name];});['run_candles','run_trades','fast_mode','benchmark','export_chart','export_csv','export_json','export_tradingview','debug_mode'].forEach(name=>{const input=form.querySelector(`[name=${name}]`);if(input)values[name]=input.checked;});if(kind==='demo'){const cfg={};['starting_balance','fee','futures_leverage'].forEach(k=>{if(values[k]!==undefined&&values[k]!==''){cfg[k]=Number(values[k]);}delete values[k];});if(Object.keys(cfg).length)values.config=cfg;if(values.lookback_days!==undefined&&values.lookback_days!=='')values.lookback_days=Number(values.lookback_days);}state.strategy=values.routes?.[0]?.strategy||values.strategy;state.chartRoute=0;state.session=await api(`/api/sessions/${kind}`,{method:'POST',body:JSON.stringify(values)});notice(`${readable(kind)} started`);watchGen++;const target=document.querySelector('#active-session');target.innerHTML=renderSession(state.session);bindSessionActions(target);if(state.session.status==='running')startWatch(state.session.session_id);else mountSessionCharts(target,state.session);}catch(error){notice(error instanceof SyntaxError?'Advanced settings must contain valid JSON':error.message,'error');}finally{busy(button,false);}}
async function loadSession(id){if(!confirmDiscard())return;try{state.session=await api(`/api/session/${id}`);state.chartRoute=0;await render();scrollToActiveSession();}catch(error){notice(error.message,'error');}}
function scrollToActiveSession(){const el=document.querySelector('#active-session');if(el)requestAnimationFrame(()=>el.scrollIntoView({behavior:'smooth',block:'start'}));}
// ───────────────────────── metric formatting & grouping ─────────────────────
const PCT_ALREADY = new Set(['net_profit_percentage','expectancy_percentage','max_drawdown','annual_return','longs_percentage','shorts_percentage']);
const PCT_FRACTION = new Set(['win_rate','win_rate_longs','win_rate_shorts']);
const MONEY = new Set(['net_profit','starting_balance','finishing_balance','fee','gross_profit','gross_loss','average_win','average_loss','largest_winning_trade','largest_losing_trade','expectancy','open_pl','expected_net_profit_every_100_trades']);
const DURATION = new Set(['average_holding_period','average_winning_holding_period','average_losing_holding_period']);
const RATIO2 = new Set(['sharpe_ratio','sortino_ratio','calmar_ratio','omega_ratio','serenity_index','ratio_avg_win_loss','avg_trades_per_day','avg_trades_per_week','avg_trades_per_month']);
const INTEGER = new Set(['total','total_winning_trades','total_losing_trades','longs_count','shorts_count','winning_streak','losing_streak','current_streak','total_open_trades']);
const METRIC_GROUPS = [
  { title:'Returns', keys:['net_profit','net_profit_percentage','annual_return','expectancy','expectancy_percentage','expected_net_profit_every_100_trades'] },
  { title:'Balance & Fees', keys:['starting_balance','finishing_balance','gross_profit','gross_loss','fee','open_pl'] },
  { title:'Risk-Adjusted', keys:['sharpe_ratio','sortino_ratio','calmar_ratio','omega_ratio','serenity_index','max_drawdown','max_underwater_period'] },
  { title:'Trades', keys:['total','total_winning_trades','total_losing_trades','win_rate','ratio_avg_win_loss','average_win','average_loss','largest_winning_trade','largest_losing_trade','winning_streak','losing_streak','current_streak'] },
  { title:'Exposure', keys:['longs_count','shorts_count','longs_percentage','shorts_percentage','win_rate_longs','win_rate_shorts','average_holding_period','average_winning_holding_period','average_losing_holding_period','avg_trades_per_day','avg_trades_per_week','avg_trades_per_month'] },
];
function fmtDuration(sec){ sec=Number(sec); if(!Number.isFinite(sec)||sec<=0) return sec===0?'0':'—'; const d=Math.floor(sec/86400),h=Math.floor(sec%86400/3600),m=Math.floor(sec%3600/60); if(d) return `${d}d ${h}h`; if(h) return `${h}h ${m}m`; if(m) return `${m}m`; return `${Math.floor(sec)}s`; }
function fmtMetric(key,value){ if(value===null||value===undefined||(typeof value==='number'&&!Number.isFinite(value))) return '—';
  if(PCT_FRACTION.has(key)) return `${fmt(value*100)}%`;
  if(PCT_ALREADY.has(key)) return `${fmt(value)}%`;
  if(DURATION.has(key)) return fmtDuration(value);
  if(key==='max_underwater_period') return `${fmt(value,0)} days`;
  if(INTEGER.has(key)) return fmt(value,0);
  if(RATIO2.has(key)) return fmt(value,2);
  if(MONEY.has(key)) return fmt(value,2);
  return fmt(value,2); }
function metricLabel(key){ return readable(key.replace(/_percentage$/,' %').replace('avg_','avg ').replace('_period',' period')); }
function metricsTables(metrics){ if(!metrics||!Object.keys(metrics).length) return '<p class="muted">No metrics.</p>';
  return `<div class="metric-tables">${METRIC_GROUPS.map(g=>{ const rows=g.keys.filter(k=>k in metrics).map(k=>`<tr><td>${esc(metricLabel(k))}</td><td class="num ${Number(metrics[k])<0?'negative':''}">${esc(fmtMetric(k,metrics[k]))}</td></tr>`).join(''); return rows?`<div class="metric-table"><h4>${esc(g.title)}</h4><table class="kv">${rows}</table></div>`:''; }).join('')}</div>`; }
function headlineCards(metrics,benchmark){ const cards=[['Net Profit',`${fmt(metrics.net_profit_percentage)}%`,Number(metrics.net_profit_percentage)>=0?'positive':'negative'],['Sharpe',fmt(metrics.sharpe_ratio),''],['Max Drawdown',`${fmt(metrics.max_drawdown)}%`,'negative'],['Win Rate',`${fmt((metrics.win_rate||0)*100)}%`,''],['Trades',fmt(metrics.total,0),'']];
  if(benchmark) cards.push(['Buy & Hold',`${fmt(benchmark.return_percentage)}%`,Number(benchmark.return_percentage)>=0?'positive':'negative']);
  return `<div class="headline-cards">${cards.map(([l,v,c])=>`<div class="headline-card"><span>${esc(l)}</span><strong class="${c}">${esc(v)}</strong></div>`).join('')}</div>`; }

// ───────────────────────── monthly heatmap & histograms ─────────────────────
function heatCell(v){ if(v===null||v===undefined) return `<td class="heat empty">·</td>`; const mag=Math.min(1,Math.abs(v)/12); const a=(0.14+mag*0.7).toFixed(2); const bg=v>=0?`rgba(77,212,155,${a})`:`rgba(255,107,107,${a})`; return `<td class="heat" style="background:${bg}">${fmt(v,1)}</td>`; }
function monthlyHeatmap(mr){ if(!mr||!mr.rows||!mr.rows.length) return '<p class="muted">Not enough data for a monthly breakdown.</p>';
  const head=`<tr><th>Year</th>${MONTH_LABELS.map(m=>`<th>${m}</th>`).join('')}<th class="total">Total</th></tr>`;
  const body=mr.rows.map(r=>`<tr><th>${r.year}</th>${r.months.map(heatCell).join('')}${r.total==null?'<td class="heat empty">·</td>':`<td class="heat total" style="background:${r.total>=0?'rgba(77,212,155,.28)':'rgba(255,107,107,.28)'}">${fmt(r.total,1)}</td>`}</tr>`).join('');
  return `<div class="table-wrap"><table class="heatmap">${head}${body}</table></div>`; }
function histogramSVG(values,{pos='#4dd49b',neg='#ff6b6b',label='',w=560,h=200}={}){ values=(values||[]).map(Number).filter(Number.isFinite); if(values.length<2) return '<p class="muted">Not enough data.</p>';
  const min=Math.min(...values),max=Math.max(...values),span=(max-min)||1; const bins=Math.max(6,Math.min(24,Math.ceil(Math.sqrt(values.length)))); const counts=new Array(bins).fill(0); values.forEach(v=>{ let i=Math.floor((v-min)/span*bins); if(i>=bins)i=bins-1; if(i<0)i=0; counts[i]++; }); const maxC=Math.max(...counts)||1; const pad=26,bw=(w-pad*2)/bins;
  const bars=counts.map((c,i)=>{ const bh=(c/maxC)*(h-pad*2); const x=pad+i*bw; const y=h-pad-bh; const center=min+(i+0.5)/bins*span; return `<rect x="${x.toFixed(1)}" y="${y.toFixed(1)}" width="${(bw-1).toFixed(1)}" height="${Math.max(0,bh).toFixed(1)}" fill="${center>=0?pos:neg}" opacity="0.85"/>`; }).join('');
  const zeroX=pad+((0-min)/span)*(w-pad*2); const zero=(0>=min&&0<=max)?`<line x1="${zeroX.toFixed(1)}" y1="${pad-6}" x2="${zeroX.toFixed(1)}" y2="${h-pad}" stroke="var(--muted)" stroke-dasharray="3 3" opacity="0.6"/>`:'';
  return `<svg class="hist" viewBox="0 0 ${w} ${h}" role="img" aria-label="${esc(label)}">${zero}${bars}<line x1="${pad}" y1="${h-pad}" x2="${w-pad}" y2="${h-pad}" stroke="var(--stroke)"/><text x="${pad}" y="${h-8}" class="hist-min">${fmt(min,1)}</text><text x="${w-pad}" y="${h-8}" class="hist-max" text-anchor="end">${fmt(max,1)}</text></svg>`; }

function toSeconds(pts){ return (pts||[]).map(p=>{ const t=Array.isArray(p)?p[0]:p.time; const v=Array.isArray(p)?p[1]:p.value; const sec=t>1e11?Math.floor(t/1000):t; return {time:sec,value:Number(v)}; }).filter(p=>Number.isFinite(p.value)); }
function dailySeries(daily,startDate){ if(!daily||!daily.length) return []; const start=Math.floor(Date.parse(`${startDate}T00:00:00Z`)/1000)||0; return daily.map((v,i)=>({time:start+i*86400,value:Number(v)})); }
function underwaterSeries(daily,startDate){ if(!daily||!daily.length) return []; const start=Math.floor(Date.parse(`${startDate}T00:00:00Z`)/1000)||0; let peak=daily[0]; return daily.map((v,i)=>{ if(v>peak)peak=v; const dd=peak?((v-peak)/peak*100):0; return {time:start+i*86400,value:dd}; }); }
function runningBlock(s,progress){return `<div class="session-running"><div class="spinner" aria-hidden="true"></div><h2>${s.status==='draft'?'Draft Ready':'Research in Progress'}</h2><p>${s.status==='draft'?'Start this session when you are ready.':'Checking progress automatically…'}</p><div class="progress" role="progressbar" aria-label="Research progress" aria-valuemin="0" aria-valuemax="100" aria-valuenow="${progress}"><i style="width:${progress}%"></i></div><strong>${progress}%</strong>${s.status==='draft'?`<button class="primary" data-run="${esc(s.session_id)}">Run Session</button>`:`<button class="danger-text" data-cancel="${esc(s.session_id)}">Cancel</button>`}</div>`;}
function resultHead(s,extra=''){const title=s.notes_metadata?.title||s.state.strategy;const live=s.kind==='demo'&&s.status==='running'&&(s.results||{}).live?.is_live;const mark=live?`<span class="live-mark"><span class="live-dot"></span> LIVE</span>`:`<span class="success-mark">● ${s.kind==='demo'?'Demo Stopped':'Finished'}</span>`;const stop=live?`<button class="danger-text small" data-cancel="${esc(s.session_id)}">Stop</button>`:'';return `<div class="result-head"><div>${mark}<h2>${esc(title)} <small>${esc(s.state.symbol)} · ${esc(s.state.timeframe)}</small></h2><p class="muted">${esc(s.state.strategy)} · ${esc(readable(s.kind))} · ${esc(s.state.start_date)} → ${esc(s.state.finish_date)}</p></div><div class="button-row">${stop}${extra}<a class="secondary small" href="/reports/${encodeURIComponent(s.session_id)}" target="_blank" rel="noopener">Report</a><a class="secondary small" href="/api/session/${encodeURIComponent(s.session_id)}/export?format=json">JSON</a><a class="secondary small" href="/api/session/${encodeURIComponent(s.session_id)}/export?format=csv">CSV</a></div></div>`;}
function sessionMeta(s){return `<div class="session-metadata"><label class="notes-label">Session Title<input data-title="${esc(s.session_id)}" name="session_title" maxlength="160" autocomplete="off" value="${esc(s.notes_metadata?.title||'')}"></label><label class="notes-label">Notes<textarea data-notes="${esc(s.session_id)}" name="session_notes" maxlength="20000" placeholder="Add a research note…">${esc(s.notes||'')}</textarea></label></div><button class="secondary small" data-save-notes="${esc(s.session_id)}">Save Details</button>`;}
function monthlyValues(mr){if(!mr||!mr.rows)return [];const out=[];mr.rows.forEach(r=>r.months.forEach(m=>{if(m!=null)out.push(m);}));return out;}
function routeSelector(s){const routes=s.state.routes||[{exchange:s.state.exchange,symbol:s.state.symbol,timeframe:s.state.timeframe,strategy:s.state.strategy}];if(routes.length<2)return '';return `<label class="route-picker">Route<select id="route-select">${routes.map((r,i)=>`<option value="${i}" ${i===(state.chartRoute||0)?'selected':''}>${esc(r.symbol)} · ${esc(r.timeframe)} · ${esc(r.strategy||'')}</option>`).join('')}</select></label>`;}
function tradesSection(trades,symbol){if(!trades||!trades.length)return '<p class="muted padded">No closed trades.</p>';const rows=trades.slice(0,300).map((t,i)=>{const cls=Number(t.PNL)>=0?'positive':'negative';const orders=(t.orders||[]).filter(o=>o.executed_at);const detail=orders.length?`<tr class="order-detail" data-detail="${i}" hidden><td colspan="10"><div class="orders"><strong>Orders</strong>${orders.map(o=>`<div class="order-row"><span class="tag ${o.side}">${esc(o.side)}</span> ${esc(o.type||'')} · ${fmt(o.qty,4)} @ ${fmt(o.price)} · ${esc(fmtDate(o.executed_at))}${o.reduce_only?' · <em>reduce</em>':''}</div>`).join('')}</div></td></tr>`:'';return `<tr class="trade-row" data-trade="${i}"><td>${i+1}</td><td><span class="tag ${esc(t.type)}">${esc(t.type)}</span></td><td class="num">${fmt(t.entry_price)}</td><td class="num">${fmt(t.exit_price)}</td><td class="num">${fmt(t.qty,4)}</td><td class="num ${cls}">${fmt(t.PNL)}</td><td class="num ${cls}">${fmt(t.PNL_percentage)}%</td><td class="num">${fmt(t.fee)}</td><td class="num">${fmtDuration(t.holding_period)}</td><td>${esc(fmtDate(t.opened_at))}</td></tr>${detail}`;}).join('');return `<div class="table-wrap"><table class="trades-table"><thead><tr><th>#</th><th>Side</th><th class="num">Entry</th><th class="num">Exit</th><th class="num">Qty</th><th class="num">PnL</th><th class="num">PnL %</th><th class="num">Fee</th><th class="num">Held</th><th>Opened</th></tr></thead><tbody>${rows}</tbody></table></div>${trades.length>300?`<p class="muted padded">Showing first 300 of ${trades.length} trades.</p>`:''}`;}
function detailsSection(s){const r=s.results||{};const hp=s.state.hyperparameters;const cfg=s.state.config;const parts=[];if(hp&&Object.keys(hp).length)parts.push(`<h4 class="sub">Hyperparameters</h4><table class="kv">${Object.entries(hp).map(([k,v])=>`<tr><td>${esc(k)}</td><td class="num">${esc(String(v))}</td></tr>`).join('')}</table>`);if(cfg&&Object.keys(cfg).length)parts.push(`<h4 class="sub">Engine Config</h4><table class="kv">${Object.entries(cfg).map(([k,v])=>`<tr><td>${esc(readable(k))}</td><td class="num">${esc(String(v))}</td></tr>`).join('')}</table>`);const logs=r.logs;if(logs){const text=Array.isArray(logs)?logs.join('\n'):String(logs);parts.push(`<h4 class="sub">Logs</h4><pre class="logs">${esc(text.slice(0,20000))}</pre>`);}parts.push(`<h4 class="sub">Notes</h4>${sessionMeta(s)}`);return parts.join('');}
function paperAccountPanel(s){const pa=(s.results||{}).paper_account;if(!pa)return '';const hasTransfers=(pa.deposits||0)>0||(pa.withdrawals||0)>0;const rows=[['Starting Balance',fmt(pa.starting_balance),'']];if(hasTransfers)rows.push(['Deposits',`+${fmt(pa.deposits)}`,'positive'],['Withdrawals',`-${fmt(pa.withdrawals)}`,'negative'],['Net Funded',fmt(pa.net_funded),'']);rows.push(['Final Equity',fmt(pa.final_equity),''],['Net P&L',`${fmt(pa.net_pnl)} (${fmt(pa.net_pnl_percentage)}%)`,Number(pa.net_pnl)>=0?'positive':'negative']);return `<div class="chart-box paper-account"><div class="chart-title">Paper Account${hasTransfers?' <span class="muted">— trading P&amp;L excludes deposits &amp; withdrawals</span>':''}</div><div class="headline-cards">${rows.map(([l,v,c])=>`<div class="headline-card"><span>${esc(l)}</span><strong class="${c}">${esc(v)}</strong></div>`).join('')}</div></div>`;}
function demoResult(s){return backtestResult(s,paperAccountPanel(s));}
function backtestResult(s,extra=''){const r=s.results||{},m=r.metrics||{};return `<div class="result">${resultHead(s)}${headlineCards(m,r.benchmark)}${extra}<div class="result-tabs" role="tablist"><button data-tab="overview" class="active">Overview</button><button data-tab="chart">Price &amp; Trades</button><button data-tab="returns">Monthly &amp; Risk</button><button data-tab="trades">Trades</button><button data-tab="details">Details</button></div><div class="tab-body"><section data-panel="overview" class="active"><div class="chart-box"><div class="chart-title">Portfolio Equity${r.benchmark_curve?' vs Buy &amp; Hold':''}</div><div class="chart-host" id="eq-chart"></div></div>${metricsTables(m)}</section><section data-panel="chart" hidden>${routeSelector(s)}<div class="chart-box"><div class="chart-host candle-host" id="price-chart"></div></div><div id="extra-charts"></div><p class="muted small-note"><span style="color:var(--green)">▲</span> buys · <span style="color:var(--red)">▼</span> sells. Indicator overlays appear when the strategy plots them.</p></section><section data-panel="returns" hidden><h4 class="sub">Monthly Returns (%)</h4>${monthlyHeatmap(r.monthly_returns)}<div class="chart-box"><div class="chart-title">Underwater — Drawdown %</div><div class="chart-host" id="uw-chart"></div></div><div class="dist-grid"><div class="chart-box"><div class="chart-title">Trade PnL Distribution (%)</div>${histogramSVG((r.trades||[]).map(t=>t.PNL_percentage),{label:'Trade PnL distribution'})}</div><div class="chart-box"><div class="chart-title">Monthly Return Distribution (%)</div>${histogramSVG(monthlyValues(r.monthly_returns),{label:'Monthly distribution'})}</div></div></section><section data-panel="trades" hidden>${tradesSection(r.trades,s.state.symbol)}</section><section data-panel="details" hidden>${detailsSection(s)}</section></div></div>`;}
function mcSummaryTable(summary){if(!summary||!Object.keys(summary).length)return '';return `<div class="table-wrap"><table class="kv mc-summary"><thead><tr><th>Metric</th><th>Original</th><th>Worst 5%</th><th>Median</th><th>Best 5%</th></tr></thead><tbody>${Object.entries(summary).map(([k,v])=>`<tr><td>${esc(readable(k))}</td><td class="num">${fmt(v.original,3)}</td><td class="num negative">${fmt(v.worst_5,3)}</td><td class="num">${fmt(v.median,3)}</td><td class="num positive">${fmt(v.best_5,3)}</td></tr>`).join('')}</tbody></table></div>`;}
function monteCarloResult(s){const r=s.results||{};const c=r.candles||{};const tr=r.trades||{};const haveCandles=!!c.summary_metrics;const haveTrades=!!(tr.summary_metrics||tr.max_drawdown);const modeSel=(haveCandles&&haveTrades)?`<label class="route-picker">Mode<select id="mc-mode"><option value="candles">Candle Resampling</option><option value="trades">Trade Shuffling</option></select></label>`:'';const verdict=c.overfit_verdict||tr.overfit_verdict;const cards=`<div class="headline-cards"><div class="headline-card"><span>Scenarios</span><strong>${fmt(c.num_scenarios||tr.num_scenarios||0,0)}</strong></div><div class="headline-card"><span>Overfit Verdict</span><strong class="verdict">${esc(readable(verdict||'—'))}</strong></div>${c.summary_metrics?.sharpe_ratio?`<div class="headline-card"><span>Sharpe (orig)</span><strong>${fmt(c.summary_metrics.sharpe_ratio.original,2)}</strong></div><div class="headline-card"><span>Sharpe (median)</span><strong>${fmt(c.summary_metrics.sharpe_ratio.median,2)}</strong></div><div class="headline-card"><span>Sharpe (worst 5%)</span><strong class="negative">${fmt(c.summary_metrics.sharpe_ratio.worst_5,2)}</strong></div>`:''}</div>`;return `<div class="result">${resultHead(s)}${cards}${modeSel}<div class="chart-box"><div class="chart-title">Equity-Curve Scenarios <span class="muted">(original in gold)</span></div><div class="chart-host mc-host" id="mc-chart"></div></div>${haveCandles?`<h4 class="sub">Candle-Resampling Distribution</h4>${mcSummaryTable(c.summary_metrics)}`:''}${haveTrades&&tr.max_drawdown?`<h4 class="sub">Trade-Shuffling — Max Drawdown Distribution</h4><table class="kv">${Object.entries(tr.max_drawdown).map(([k,v])=>`<tr><td>${esc(readable(k))}</td><td class="num">${fmt(v)}</td></tr>`).join('')}</table>`:''}${sessionMeta(s)}</div>`;}
function significanceResult(s){const r=(s.results||{}).results||s.results||{};const p=r.p_value;const sig=p!=null&&p<0.05;const cards=`<div class="headline-cards"><div class="headline-card"><span>P-Value</span><strong class="${sig?'positive':'negative'}">${fmt(p,4)}</strong></div><div class="headline-card"><span>Verdict</span><strong class="verdict">${esc(readable(r.verdict||(sig?'significant':'not significant')))}</strong></div><div class="headline-card"><span>Observations</span><strong>${fmt(r.n_observations,0)}</strong></div>${r.observed_mean!=null?`<div class="headline-card"><span>Observed Mean</span><strong>${fmt(r.observed_mean,6)}</strong></div>`:''}</div>`;const rows=Object.entries(r).filter(([k,v])=>typeof v!=='object').map(([k,v])=>`<tr><td>${esc(readable(k))}</td><td class="num">${typeof v==='number'?fmt(v,6):esc(String(v))}</td></tr>`).join('');return `<div class="result">${resultHead(s)}${cards}<h4 class="sub">Statistics</h4><table class="kv">${rows}</table>${sessionMeta(s)}</div>`;}
function optimizationResult(s){const r=s.results||{};const best=r.best||{};const cands=r.candidates||[];const cards=`<div class="headline-cards"><div class="headline-card"><span>Objective</span><strong>${esc(readable(r.objective||''))}</strong></div><div class="headline-card"><span>Best Train</span><strong>${fmt(best.train_score,3)}</strong></div><div class="headline-card"><span>Best Test</span><strong>${fmt(best.test_score,3)}</strong></div><div class="headline-card"><span>Candidates</span><strong>${fmt(cands.length,0)}</strong></div></div>`;const table=cands.length?`<div class="table-wrap"><table class="trades-table"><thead><tr><th>#</th><th>Hyperparameters</th><th class="num">Train</th><th class="num">Test</th></tr></thead><tbody>${cands.map((c,i)=>`<tr><td>${i+1}</td><td><code>${esc(JSON.stringify(c.hp))}</code></td><td class="num">${fmt(c.train_score,3)}</td><td class="num">${fmt(c.test_score,3)}</td></tr>`).join('')}</tbody></table></div>`:'<p class="muted">No candidates.</p>';return `<div class="result">${resultHead(s)}${cards}${best.hp?`<h4 class="sub">Best Parameters</h4><pre class="logs">${esc(JSON.stringify(best.hp,null,2))}</pre>`:''}<h4 class="sub">Candidates</h4>${table}${sessionMeta(s)}</div>`;}
function liveConnectingBlock(s){const err=(s.results||{}).message;return `<div class="session-running"><div class="spinner" aria-hidden="true"></div><h2>Connecting to the live market…</h2><p>${err?esc(err):'Fetching recent candles and starting paper trading. The full report appears here as soon as the first window is replayed.'}</p><button class="danger-text" data-cancel="${esc(s.session_id)}">Stop Demo</button></div>`;}
function renderSession(s){const result=s.results||{};const progress=Math.max(0,Math.min(100,Number(s.progress)||0));if(s.kind==='demo'){if(result.metrics)return demoResult(s);if(s.status==='running'||s.status==='draft')return liveConnectingBlock(s);return `<div class="error-state"><h2>Demo Stopped</h2><p>${esc(result.message||result.error||'The live demo did not produce results.')}</p><button class="secondary" data-run="${esc(s.session_id)}">Restart</button></div>`;}if(s.status==='running'||s.status==='draft')return runningBlock(s,progress);if(s.status!=='finished')return `<div class="error-state"><h2>${s.status==='canceled'?'Session Canceled':'Session Stopped'}</h2><p>${esc(result.message||result.error||'This session did not complete.')}</p><button class="secondary" data-run="${esc(s.session_id)}">Try Again</button></div>`;if(s.kind==='backtest')return backtestResult(s);if(s.kind==='monte_carlo')return monteCarloResult(s);if(s.kind==='significance_test')return significanceResult(s);if(s.kind==='optimization')return optimizationResult(s);return '<p class="muted">This completed session has no displayable summary.</p>';}
// ── mount lightweight-charts once a finished session's HTML is in the DOM ──
function mountSessionCharts(container,s){if(!container||!s)return;const showReport=s.status==='finished'||(s.kind==='demo'&&s.status==='running'&&(s.results||{}).metrics);if(!showReport)return;const tabs=[...container.querySelectorAll('.result-tabs [data-tab]')];const panels=[...container.querySelectorAll('[data-panel]')];const mounted=new Set();const mountTab=name=>{if(name==='overview'){const eq=container.querySelector('#eq-chart');if(eq){const series=[{name:'Portfolio',data:toSeconds(s.results.equity_curve)}];if(s.results.benchmark_curve)series.push({name:'Buy & Hold',data:toSeconds(s.results.benchmark_curve)});charts.lineChart(eq,series,{area:true,height:320});}}else if(name==='chart'){loadPriceChart(container,s);}else if(name==='returns'){const uw=container.querySelector('#uw-chart');if(uw)charts.areaChart(uw,underwaterSeries(s.results.daily_balance,s.state.start_date),{height:200});}};const activate=name=>{tabs.forEach(t=>t.classList.toggle('active',t.dataset.tab===name));panels.forEach(p=>{const on=p.dataset.panel===name;p.classList.toggle('active',on);p.hidden=!on;});if(!mounted.has(name)){mounted.add(name);mountTab(name);}};tabs.forEach(t=>t.addEventListener('click',()=>activate(t.dataset.tab)));const def=panels.find(p=>p.classList.contains('active'));if(def){mounted.add(def.dataset.panel);mountTab(def.dataset.panel);}
  container.querySelectorAll('.trade-row').forEach(row=>row.addEventListener('click',()=>{const d=container.querySelector(`[data-detail="${row.dataset.trade}"]`);if(d)d.hidden=!d.hidden;}));
  const rs=container.querySelector('#route-select');if(rs)rs.addEventListener('change',()=>{state.chartRoute=Number(rs.value)||0;liveChartView=null;loadPriceChart(container,s);});
  if(s.kind==='monte_carlo'){loadMcChart(container,s,'candles');const ms=container.querySelector('#mc-mode');if(ms)ms.addEventListener('change',()=>loadMcChart(container,s,ms.value));}}
async function loadPriceChart(container,s){const price=container.querySelector('#price-chart');const extra=container.querySelector('#extra-charts');if(!price)return;const live=s.kind==='demo'&&!!(s.results||{}).live?.is_live;price.innerHTML='<div class="chart-loading">Loading candles…</div>';try{const data=await api(`/api/session/${s.session_id}/candles?route=${state.chartRoute||0}`);if(!data.candles||!data.candles.length){price.innerHTML='<p class="muted padded">No candle data stored for this route. Re-import candles for this range.</p>';return;}charts.priceChart(price,data,{extraEl:extra,live,view:live?liveChartView:null,onView:live?(r,barCount)=>{liveChartView={from:r.from,to:r.to,width:r.to-r.from,follow:r.to>=barCount-1};}:null});}catch(error){price.innerHTML=`<p class="muted padded">${esc(error.message)}</p>`;}}
async function loadMcChart(container,s,mode){const el=container.querySelector('#mc-chart');if(!el)return;el.innerHTML='<div class="chart-loading">Loading scenarios…</div>';try{const data=await api(`/api/session/${s.session_id}/monte-carlo-curves`);const set=data[mode]||data.candles||data.trades;if(!set||!set.scenarios){el.innerHTML='<p class="muted padded">No equity-curve scenarios were stored for this session.</p>';return;}charts.montecarloChart(el,{original:set.original,scenarios:set.scenarios},{height:360});}catch(error){el.innerHTML=`<p class="muted padded">${esc(error.message)}</p>`;}}
function startWatch(id){const gen=++watchGen;lastDemoUpdate=null;liveChartView=null;watchSession(id,gen);}
async function watchSession(id,gen){if(gen!==watchGen)return;const target=document.querySelector('#active-session');if(!target)return;try{const s=await api(`/api/session/${id}`);if(gen!==watchGen)return;
  // A live demo stays "running" and streams updated results (status may briefly be
  // "canceled" while it finalizes after Stop). Keep polling, but only re-render when
  // the data actually changed so the chart tabs don't reset every few seconds.
  const demoLive=s.kind==='demo'&&(s.status==='running'||s.status==='canceled');
  const upd=s.results?.live?.updated_at??null;
  if(demoLive&&(s.results||{}).metrics&&upd!==null&&upd===lastDemoUpdate&&state.session){setTimeout(()=>watchSession(id,gen),4000);return;}
  lastDemoUpdate=upd;state.session=s;
  const prevTab=s.kind==='demo'?target.querySelector('.result-tabs [data-tab].active')?.dataset.tab:null;
  target.innerHTML=renderSession(s);bindSessionActions(target);charts.disposeCharts();mountSessionCharts(target,s);
  if(prevTab&&prevTab!=='overview')target.querySelector(`.result-tabs [data-tab="${prevTab}"]`)?.click();
  if(s.status==='running'||demoLive){setTimeout(()=>watchSession(id,gen),s.kind==='demo'?4000:900);}
  else{const done=s.status==='finished';notice(s.kind==='demo'?'Demo stopped — final results saved':(done?'Research finished':s.results?.message||'Research stopped'),done||s.kind==='demo'?'success':'error');if(done)setTimeout(render,0);}
}catch(error){if(gen===watchGen)notice(error.message,'error');}}
function bindSessionActions(container=document){container.querySelectorAll('[data-run]').forEach(btn=>btn.addEventListener('click',async()=>{try{state.session=await api(`/api/session/${btn.dataset.run}/run`,{method:'POST'});startWatch(btn.dataset.run);}catch(error){notice(error.message,'error');}}));container.querySelectorAll('[data-cancel]').forEach(btn=>btn.addEventListener('click',async()=>{if(!confirm('Cancel this research session?'))return;try{state.session=await api(`/api/session/${btn.dataset.cancel}/cancel`,{method:'POST'});startWatch(btn.dataset.cancel);}catch(error){notice(error.message,'error');}}));container.querySelectorAll('[data-delete-session]').forEach(btn=>btn.addEventListener('click',async()=>{if(!confirm('Delete this saved session? This cannot be undone.'))return;try{await api(`/api/session/${btn.dataset.deleteSession}`,{method:'DELETE'});if(state.session?.session_id===btn.dataset.deleteSession)state.session=null;notice('Session deleted');render();}catch(error){notice(error.message,'error');}}));container.querySelectorAll('[data-notes],[data-title]').forEach(input=>input.addEventListener('input',()=>{state.dirty=true;state.dirtyReason='session detail changes';}));container.querySelectorAll('[data-save-notes]').forEach(btn=>btn.addEventListener('click',async()=>{try{const id=btn.dataset.saveNotes;state.session=await api(`/api/session/${id}`,{method:'PATCH',body:JSON.stringify({title:document.querySelector(`[data-title="${id}"]`).value,notes:document.querySelector(`[data-notes="${id}"]`).value})});state.dirty=false;state.dirtyReason=null;notice('Session details saved');await render();}catch(error){notice(error.message,'error');}}));}

async function indicators(){const data=await api('/api/indicators');shell('Indicators',`<div class="split indicators"><aside class="list-panel"><div class="panel-head"><strong>${data.count} indicators</strong></div><input id="indicator-search" name="indicator_search" autocomplete="off" aria-label="Search indicators" placeholder="Search indicators…"><div class="indicator-list">${data.indicators.map(name=>`<button data-indicator="${esc(name)}">${esc(name)}</button>`).join('')}</div></aside><section class="workspace" id="indicator-detail">${empty('Choose an indicator','Select an indicator to see its callable signature and documentation.')}</section></div>`,'All indicators are locally available to strategies and MCP clients.');document.querySelector('#indicator-search').addEventListener('input',event=>{const query=event.target.value.toLowerCase();document.querySelectorAll('[data-indicator]').forEach(row=>row.hidden=!row.textContent.toLowerCase().includes(query));});document.querySelectorAll('[data-indicator]').forEach(button=>button.addEventListener('click',async()=>{try{const d=await api(`/api/indicators/${encodeURIComponent(button.dataset.indicator)}`);document.querySelector('#indicator-detail').innerHTML=`<div class="indicator-doc"><span class="badge">INDICATOR</span><h2>${esc(d.name)}</h2><code>${esc(d.signature)}</code><pre>${esc(d.doc||'No documentation available.')}</pre><div class="callout">Use <code>ta.${esc(d.name)}(self.candles)</code>; add <code>sequential=True</code> when supported for a full series.</div></div>`;}catch(error){notice(error.message,'error');}}));}

async function settings(){const data=await api('/api/config');const c=data.config;shell('Settings',`<div class="settings"><section class="panel"><div class="panel-head"><div><h2>Backtest Defaults</h2><p>These saved values initialize new research sessions.</p></div></div><form class="form-grid" id="settings-form" autocomplete="off"><label>Exchange<select name="exchange">${state.status.supported_exchanges.map(v=>`<option ${v===c.exchange?'selected':''}>${esc(v)}</option>`).join('')}</select></label><label>Market Type<select name="type"><option ${c.type==='futures'?'selected':''}>futures</option><option ${c.type==='spot'?'selected':''}>spot</option></select></label><label>Starting Balance<input type="number" inputmode="decimal" min="0.01" step="any" name="starting_balance" value="${esc(c.starting_balance)}"></label><label>Fee Rate<input type="number" inputmode="decimal" min="0" max="1" step="0.0001" name="fee" value="${esc(c.fee)}"></label><label>Leverage<input type="number" inputmode="decimal" min="1" step="any" name="futures_leverage" value="${esc(c.futures_leverage)}"></label><label>Warm-Up Candles<input type="number" inputmode="numeric" min="0" step="1" name="warm_up_candles" value="${esc(c.warm_up_candles)}"></label><div class="form-actions"><button class="primary">Save Settings</button></div></form></section><section class="panel capabilities"><h2>Capabilities</h2><ul class="feature-list"><li><span aria-hidden="true">●</span> Local SQLite storage</li><li><span aria-hidden="true">●</span> Ten Jesse backtest exchanges</li><li><span aria-hidden="true">●</span> MCP, ML, optimization, and robustness research</li><li class="disabled"><span aria-hidden="true">○</span> Live and paper trading require a separate execution product</li></ul></section></div>`,'Configuration is stored only in this Terry project.');document.querySelector('#settings-form').addEventListener('submit',async event=>{event.preventDefault();const form=event.currentTarget,button=form.querySelector('button');const values=Object.fromEntries(new FormData(form));['starting_balance','fee','futures_leverage','warm_up_candles'].forEach(k=>values[k]=Number(values[k]));busy(button,true);try{await api('/api/config',{method:'PATCH',body:JSON.stringify(values)});notice('Settings saved');state.status=await api('/api/status');}catch(error){notice(error.message,'error');}finally{busy(button,false);}});}
function live(){shell('Live Trading',`<section class="panel unavailable"><span class="badge">NOT AVAILABLE</span><h2>Local research, not execution.</h2><p>Terry intentionally does not connect to exchange accounts or place real or paper orders. Use the backtest, Rule Test, Monte Carlo, and optimization workflows to research a strategy before considering any external execution system.</p><button class="primary" data-route="backtest">Open Backtest</button></section>`,'This product does not implement the Jesse live-trading plugin.');document.querySelector('[data-route]')?.addEventListener('click',()=>setRoute('backtest'));}

async function render(){watchGen++;try{charts.disposeCharts();const current=route();if(current==='home')await home();else if(current==='strategies')await strategies();else if(current==='candles')await candles();else if(modes[current])await research(current);else if(current==='indicators')await indicators();else if(current==='settings')await settings();else if(current==='live')live();else setRoute('home');bindSessionActions();}catch(error){shell('Something went wrong',`<section class="panel error-state"><h2>Unable to load this view</h2><p>${esc(error.message)}</p><button class="primary" id="retry">Try again</button></section>`);document.querySelector('#retry').addEventListener('click',render);}}
async function boot(){try{const auth=await api('/api/auth/status');if(auth.auth_required&&!auth.authenticated){login();return;}state.status=await api('/api/status');state.currentRoute=route();await render();}catch(error){app.innerHTML=`<section class="login"><div class="login-card"><h1>Terry Is Unavailable</h1><p>${esc(error.message)}</p><button class="primary" id="reload">Retry</button></div></section>`;document.querySelector('#reload')?.addEventListener('click',()=>location.reload());}}
window.addEventListener('beforeunload',event=>{if(state.dirty){event.preventDefault();event.returnValue='';}});
window.addEventListener('hashchange',()=>{if(!state.status)return;const next=route();if(state.dirty&&state.currentRoute&&next!==state.currentRoute){if(!confirmDiscard()){history.replaceState(null,'',`${location.pathname}${location.search}#/${state.currentRoute}`);return;}}state.currentRoute=next;render();});
document.addEventListener('keydown',event=>{if(event.key==='Escape'){document.body.classList.remove('menu-open');document.querySelector('.menu-button')?.setAttribute('aria-expanded','false');}});
applyTheme();boot();
